// Chequea n8n Mica y n8n Lovbot
// FastAPI + n8n Arnaldo los cubre la guardia_critica.py (script independiente)
// Variables de entorno: N8N_MICA_URL, N8N_LOVBOT_URL

const N8N_MICA_URL = process.env.N8N_MICA_URL || 'https://sytem-ia-pruebas-n8n.6g0gdj.easypanel.host';
const N8N_LOVBOT_URL = process.env.N8N_LOVBOT_URL || 'https://n8n.lovbot.ai';

async function checkHealth(nombre, url) {
  try {
    const response = await $http.request({
      method: 'GET',
      url: `${url}/healthz`,
      timeout: 10000,
    });
    if (response && (response.status === 200 || response.status === 'ok')) {
      return { servicio: nombre, ok: true, detalle: 'responde' };
    }
    return { servicio: nombre, ok: false, tipo: 'infraestructura_caida', detalle: `HTTP inesperado` };
  } catch (e) {
    return { servicio: nombre, ok: false, tipo: 'infraestructura_caida', detalle: `no responde: ${e.message}` };
  }
}

const resultados = await Promise.all([
  checkHealth('n8n Mica', N8N_MICA_URL),
  checkHealth('n8n Lovbot', N8N_LOVBOT_URL),
]);

const alertas = resultados.filter(r => !r.ok);

return [{ json: { resultados, alertas, total_alertas: alertas.length } }];

// Chequea estado activo de workflows críticos en las 3 instancias
// Usa las APIs de n8n via HTTP con credenciales en env vars
// Variables: N8N_ARNALDO_URL, N8N_ARNALDO_KEY, N8N_MICA_URL, N8N_MICA_KEY, N8N_LOVBOT_URL, N8N_LOVBOT_KEY

const N8N_ARNALDO_URL = process.env.N8N_ARNALDO_URL || 'https://n8n.arnaldoayalaestratega.cloud';
const N8N_ARNALDO_KEY = process.env.N8N_ARNALDO_KEY || '';
const N8N_MICA_URL    = process.env.N8N_MICA_URL    || 'https://sytem-ia-pruebas-n8n.6g0gdj.easypanel.host';
const N8N_MICA_KEY    = process.env.N8N_MICA_KEY    || '';
const N8N_LOVBOT_URL  = process.env.N8N_LOVBOT_URL  || 'https://n8n.lovbot.ai';
const N8N_LOVBOT_KEY  = process.env.N8N_LOVBOT_KEY  || '';

const WORKFLOWS_CRITICOS = [
  { id: 'o4CrjByltFurUWox', nombre: 'Bot Maicol',        instancia: 'arnaldo', url: N8N_ARNALDO_URL, key: N8N_ARNALDO_KEY },
  { id: 'aJILcfjRoKDFvGWY', nombre: 'Redes Arnaldo',     instancia: 'arnaldo', url: N8N_ARNALDO_URL, key: N8N_ARNALDO_KEY },
  { id: 'yE7fwesbdjxIxoDn', nombre: 'Alerta Cuotas Maicol', instancia: 'arnaldo', url: N8N_ARNALDO_URL, key: N8N_ARNALDO_KEY },
  { id: 'aOiZFbmvMoPSE0vB', nombre: 'Redes Mica',        instancia: 'mica',    url: N8N_MICA_URL,    key: N8N_MICA_KEY },
  { id: 'OyTCUWbtnigfu5Oh', nombre: 'Lovbot Eventos',    instancia: 'lovbot',  url: N8N_LOVBOT_URL,  key: N8N_LOVBOT_KEY },
  { id: 'vF3bMbCzFz3D2W9z', nombre: 'Lovbot Onboarding', instancia: 'lovbot',  url: N8N_LOVBOT_URL,  key: N8N_LOVBOT_KEY },
  { id: 'zEyLpnNJeapT9auj', nombre: 'Lovbot Login Code', instancia: 'lovbot',  url: N8N_LOVBOT_URL,  key: N8N_LOVBOT_KEY },
];

async function checkWorkflow(wf) {
  try {
    const response = await $http.request({
      method: 'GET',
      url: `${wf.url}/api/v1/workflows/${wf.id}`,
      headers: { 'X-N8N-API-KEY': wf.key },
      timeout: 10000,
    });
    const data = response;
    if (!data || data.id === undefined) {
      return { id: wf.id, nombre: wf.nombre, instancia: wf.instancia, ok: false, tipo: 'workflow_inexistente', detalle: 'no encontrado en la instancia' };
    }
    if (data.active === false) {
      return { id: wf.id, nombre: wf.nombre, instancia: wf.instancia, ok: false, tipo: 'workflow_inactivo', detalle: 'active=false' };
    }
    return { id: wf.id, nombre: wf.nombre, instancia: wf.instancia, ok: true, detalle: 'activo' };
  } catch (e) {
    const status = e.response?.status;
    if (status === 404) {
      return { id: wf.id, nombre: wf.nombre, instancia: wf.instancia, ok: false, tipo: 'workflow_inexistente', detalle: 'HTTP 404' };
    }
    return { id: wf.id, nombre: wf.nombre, instancia: wf.instancia, ok: false, tipo: 'workflow_inactivo', detalle: `error: ${e.message}` };
  }
}

const resultados = await Promise.all(WORKFLOWS_CRITICOS.map(checkWorkflow));
const alertas = resultados.filter(r => !r.ok);

return [{ json: { resultados, alertas, total_alertas: alertas.length } }];

// Chequea si las últimas ejecuciones de workflows con schedule automático fallaron
// Ventana: últimas 26 horas
// Workflows: Redes Arnaldo, Redes Mica, Backup N8N

const N8N_ARNALDO_URL = process.env.N8N_ARNALDO_URL || 'https://n8n.arnaldoayalaestratega.cloud';
const N8N_ARNALDO_KEY = process.env.N8N_ARNALDO_KEY || '';
const N8N_MICA_URL    = process.env.N8N_MICA_URL    || 'https://sytem-ia-pruebas-n8n.6g0gdj.easypanel.host';
const N8N_MICA_KEY    = process.env.N8N_MICA_KEY    || '';

const WORKFLOWS_SCHEDULE = [
  { id: 'aJILcfjRoKDFvGWY', nombre: 'Redes Arnaldo', url: N8N_ARNALDO_URL, key: N8N_ARNALDO_KEY },
  { id: 'aOiZFbmvMoPSE0vB', nombre: 'Redes Mica',    url: N8N_MICA_URL,    key: N8N_MICA_KEY },
  { id: 'fbGdj63Ry7QIw9eL', nombre: 'Backup N8N',    url: N8N_ARNALDO_URL, key: N8N_ARNALDO_KEY },
];

const VENTANA_MS = 26 * 60 * 60 * 1000; // 26 horas
const ahora = Date.now();

async function checkEjecuciones(wf) {
  try {
    const response = await $http.request({
      method: 'GET',
      url: `${wf.url}/api/v1/executions?workflowId=${wf.id}&limit=5`,
      headers: { 'X-N8N-API-KEY': wf.key },
      timeout: 10000,
    });
    const execuciones = response?.data || [];
    if (execuciones.length === 0) {
      return { nombre: wf.nombre, ok: true, detalle: 'sin ejecuciones recientes' };
    }
    // Filtrar las últimas 26h
    const recientes = execuciones.filter(e => {
      const t = new Date(e.startedAt || e.createdAt).getTime();
      return (ahora - t) < VENTANA_MS;
    });
    if (recientes.length === 0) {
      return { nombre: wf.nombre, ok: true, detalle: 'sin ejecuciones en 26h' };
    }
    // Si la última ejecución reciente tiene error
    const ultima = recientes[0];
    if (ultima.status === 'error' || ultima.status === 'crashed') {
      return {
        nombre: wf.nombre, ok: false,
        tipo: 'ejecucion_con_error',
        detalle: `última ejecución: ${ultima.status} a las ${new Date(ultima.startedAt).toLocaleString('es-AR', {timeZone: 'America/Argentina/Buenos_Aires'})}`
      };
    }
    return { nombre: wf.nombre, ok: true, detalle: `última ejecución: ${ultima.status}` };
  } catch (e) {
    return { nombre: wf.nombre, ok: false, tipo: 'ejecucion_con_error', detalle: `error consultando ejecuciones: ${e.message}` };
  }
}

const resultados = await Promise.all(WORKFLOWS_SCHEDULE.map(checkEjecuciones));
const alertas = resultados.filter(r => !r.ok);

return [{ json: { resultados, alertas, total_alertas: alertas.length } }];

// Recibe los 3 resultados y construye el reporte
// Separa alertas por tipo: infraestructura_caida, workflow_inactivo, workflow_inexistente, ejecucion_con_error

const items = $input.all();

// Los items vienen en orden: infra [0], workflows [1], ejecuciones [2]
// Pero con multiplex pueden llegar combinados — los buscamos por contenido
let alertas_infra = [];
let alertas_workflows = [];
let alertas_ejecuciones = [];

for (const item of items) {
  const d = item.json;
  if (d.resultados) {
    for (const r of d.resultados) {
      if (!r.ok) {
        if (r.tipo === 'infraestructura_caida') alertas_infra.push(r);
        else if (r.tipo === 'workflow_inactivo') alertas_workflows.push(r);
        else if (r.tipo === 'workflow_inexistente') alertas_workflows.push(r);
        else if (r.tipo === 'ejecucion_con_error') alertas_ejecuciones.push(r);
        else alertas_infra.push(r); // fallback
      }
    }
  }
}

const total = alertas_infra.length + alertas_workflows.length + alertas_ejecuciones.length;
const fecha = new Date().toLocaleString('es-AR', { timeZone: 'America/Argentina/Buenos_Aires' });

if (total === 0) {
  return [{ json: { hay_alertas: false, total: 0, mensaje: null, fecha } }];
}

// Construir mensaje Telegram
let lineas = [`🔍 <b>AUDITORÍA DIARIA</b> — ${fecha}`, ''];

if (alertas_infra.length > 0) {
  lineas.push('🏗️ <b>INFRAESTRUCTURA:</b>');
  for (const a of alertas_infra) {
    lineas.push(`  ❌ ${a.servicio || a.nombre} — ${a.detalle}`);
  }
  lineas.push('');
}

if (alertas_workflows.length > 0) {
  // Separar inactivos de inexistentes
  const inactivos = alertas_workflows.filter(a => a.tipo === 'workflow_inactivo');
  const inexistentes = alertas_workflows.filter(a => a.tipo === 'workflow_inexistente');

  if (inactivos.length > 0) {
    lineas.push('📋 <b>WORKFLOWS INACTIVOS:</b>');
    for (const a of inactivos) {
      lineas.push(`  ⏸ ${a.nombre} [${a.instancia}]`);
    }
    lineas.push('');
  }
  if (inexistentes.length > 0) {
    lineas.push('❓ <b>WORKFLOWS NO ENCONTRADOS:</b>');
    for (const a of inexistentes) {
      lineas.push(`  ❓ ${a.nombre} [${a.instancia}] — ${a.detalle}`);
    }
    lineas.push('');
  }
}

if (alertas_ejecuciones.length > 0) {
  lineas.push('🔄 <b>EJECUCIONES CON ERROR:</b>');
  for (const a of alertas_ejecuciones) {
    lineas.push(`  ❌ ${a.nombre} — ${a.detalle}`);
  }
  lineas.push('');
}

lineas.push(`⚠️ <b>${total} alerta${total > 1 ? 's' : ''} detectada${total > 1 ? 's' : ''}</b> — revisá el panel`);

const mensaje = lineas.join('\n');
return [{ json: { hay_alertas: true, total, mensaje, fecha } }];

